use soroban_sdk::testutils::{Address as _, Ledger as _};
use soroban_sdk::{contract, contractimpl, Address, Env, Symbol, token, Vec};
use sorosusu_contracts::{SoroSusuClient, SoroSusu, DefaultRecoveryConfig, RecoverySprintStatus, DebtRestructuringStatus};
  #[contract] pub struct MockToken;  #[contractimpl] impl MockToken {     pub fn init_mock(_env: Env, _admin: Address) {}     pub fn mint(_env: Env, _to: Address, _amount: i128) {}     pub fn balance(_env: Env, _addr: Address) -> i128 { 1_000_000_000 } }  const RECOVERY_SPRINT_DURATION: u64 = 86400 * 14; const PRIORITY_CLAIM_BPS: u32 = 1000; const HEALTHY_MEMBER_BPS: u32 = 5000; const MAX_SPRINT_PARTICIPANTS: u32 = 20; const MIN_PARTICIPANT_SCORE: u32 = 3000; const COLLATERAL_RELEASE_BPS: u32 = 2500; const DEBT_RESTRUCTURING_INTEREST_BPS: u32 = 1000;  #[test] fn test_configure_default_recovery_basic() {     let env = Env::default();     env.mock_all_auths();     let admin = Address::generate(&env);     let creator = Address::generate(&env);     let token = env.register_contract(None, MockToken);     let contract_id = env.register_contract(None, SoroSusu);     let client = SoroSusuClient::new(&env, &contract_id);     client.init(&admin, &0);          let circle_id = client.create_circle(&creator, &100_000_000, &10, &token, &86400, &100i128);     let config = DefaultRecoveryConfig {         enabled: true,         sprint_duration: RECOVERY_SPRINT_DURATION,         priority_claim_bps: PRIORITY_CLAIM_BPS,         healthy_member_bps: HEALTHY_MEMBER_BPS,         max_sprint_participants: MAX_SPRINT_PARTICIPANTS,         min_participant_score: MIN_PARTICIPANT_SCORE,         collateral_release_bps: COLLATERAL_RELEASE_BPS,     };     client.configure_default_recovery(&admin, &circle_id, &config); }  #[test] fn test_initiate_recovery_sprint_success() {     let env = Env::default();     env.mock_all_auths();     let admin = Address::generate(&env);     let creator = Address::generate(&env);     let defaulter = Address::generate(&env);     let token = env.register_contract(None, MockToken);     let contract_id = env.register_contract(None, SoroSusu);     let client = SoroSusuClient::new(&env, &contract_id);     client.init(&admin, &0);          let circle_id = client.create_circle(&creator, &100_000_000, &10, &token, &86400, &100i128);     client.initiate_recovery_sprint(&admin, &circle_id, &defaulter); }  #[test] fn test_debt_restructuring() {     let env = Env::default();     env.mock_all_auths();     let admin = Address::generate(&env);     let creator = Address::generate(&env);     let defaulter = Address::generate(&env);     let token = env.register_contract(None, MockToken);     let contract_id = env.register_contract(None, SoroSusu);     let client = SoroSusuClient::new(&env, &contract_id);     client.init(&admin, &0);          let circle_id = client.create_circle(&creator, &100_000_000, &10, &token, &86400, &100i128);     client.initiate_debt_restructuring(&admin, &circle_id, &defaulter, &200_000_000, &DEBT_RESTRUCTURING_INTEREST_BPS); }
